  1	import * as React from 'react';
  2	import { AccessKeyMetadata } from '@aws-sdk/client-iam';
  3	import { MAX_ACCESS_KEYS } from '@odf/core/constants/s3-iam';
  4	import { GenerateAnotherAccessKeyModal } from '@odf/core/modals/s3-iam/GenerateAnotherAccessKeyModal';
  5	import { IamUserDetails } from '@odf/core/types';
  6	import { useCustomTranslation } from '@odf/shared';
  7	import { LoadingBox, StatusBox } from '@odf/shared/generic/status-box';
  8	import { IamCommands } from '@odf/shared/iam';
  9	import { useModal } from '@openshift-console/dynamic-plugin-sdk';
 10	import {
 11	  Alert,
 12	  AlertVariant,
 13	  Button,
 14	  Grid,
 15	  EmptyState,
 16	  EmptyStateActions,
 17	  EmptyStateFooter,
 18	  EmptyStateHeader,
 19	  EmptyStateIcon,
 20	  EmptyStateVariant,
 21	} from '@patternfly/react-core';
 22	import { KeyIcon, PlusCircleIcon } from '@patternfly/react-icons';
 23	import { useUserAccessKeys } from '../hooks/useUserAccessKeys';
 24	import { useUserDetails } from '../hooks/useUserDetails';
 25	import AccessKeyCard from './AccessKeyCard';
 26	
 27	type IamAccesskeysDetailsProps = {
 28	  obj: IamUserDetails;
 29	};
 30	
 31	type AccessKeysDetailsContentProps = {
 32	  userName: string;
 33	  iamClient: IamCommands;
 34	  triggerRefresh: () => void;
 35	};
 36	
 37	const AccessKeysDetailsContent: React.FC<AccessKeysDetailsContentProps> = ({
 38	  userName,
 39	  iamClient,
 40	  triggerRefresh,
 41	}) => {
 42	  const { t } = useCustomTranslation();
 43	  const launchModal = useModal();
 44	
 45	  // Fetch user details (for tags)
 46	  const {
 47	    userDetails,
 48	    isLoading: isLoadingUserDetails,
 49	    error: userDetailsError,
 50	  } = useUserDetails(userName, iamClient);
 51	
 52	  // Fetch user access keys
 53	  const {
 54	    iamAccessKeys,
 55	    isLoading: isLoadingAccessKeys,
 56	    error: accessKeysError,
 57	  } = useUserAccessKeys(userName, iamClient);
 58	
 59	  const tags = userDetails?.Tags || [];
 60	  const isLoading = isLoadingUserDetails || isLoadingAccessKeys;
 61	  const error = userDetailsError || accessKeysError;
 62	
 63	  const launchModalOnClick = React.useCallback(() => {
 64	    launchModal(GenerateAnotherAccessKeyModal, {
 65	      isOpen: true,
 66	      userName,
 67	      refreshTokens: triggerRefresh,
 68	      iamClient,
 69	    });
 70	  }, [launchModal, userName, triggerRefresh, iamClient]);
 71	
 72	  if (isLoading || error) {
 73	    return <StatusBox loaded={!isLoading} loadError={error} />;
 74	  }
 75	
 76	  return (
 77	    <div className="odf-m-pane__body">
 78	      <div className="pf-v6-u-mt-md">
 79	        <Alert
 80	          title={t('You can define only {{maxKeys}} access keys', {
 81	            maxKeys: MAX_ACCESS_KEYS,
 82	          })}
 83	          variant={AlertVariant.info}
 84	          isInline
 85	        >
 86	          {t(
 87	            'An access key enables secure access to Object storage resources.'
 88	          )}
 89	        </Alert>
 90	        <Grid hasGutter>
 91	          {iamAccessKeys.map(
 92	            (iamAccessKey: AccessKeyMetadata, index: number) => (
 93	              <AccessKeyCard
 94	                key={iamAccessKey.AccessKeyId}
 95	                accessKeyCard={iamAccessKey}
 96	                accessKeyNumber={index + 1}
 97	                tags={tags}
 98	                refreshTokens={triggerRefresh}
 99	                iamClient={iamClient}
100	              />
101	            )
102	          )}
103	        </Grid>
104	        {iamAccessKeys.length === 0 && (
105	          <EmptyState variant={EmptyStateVariant.lg}>
106	            <EmptyStateHeader
107	              titleText={t('No access keys found')}
108	              icon={<EmptyStateIcon icon={KeyIcon} />}
109	              headingLevel="h4"
110	            />
111	            <EmptyStateFooter>
112	              <EmptyStateActions>
113	                <Button
114	                  variant="secondary"
115	                  onClick={launchModalOnClick}
116	                  icon={<PlusCircleIcon />}
117	                  aria-label={t('Generate access key')}
118	                >
119	                  {t('Generate access key')}
120	                </Button>
121	              </EmptyStateActions>
122	            </EmptyStateFooter>
123	          </EmptyState>
124	        )}
125	        {iamAccessKeys.length > 0 && iamAccessKeys.length < MAX_ACCESS_KEYS && (
126	          <Button
127	            variant="secondary"
128	            onClick={launchModalOnClick}
129	            icon={<PlusCircleIcon />}
130	            aria-label={t('Generate another access key')}
131	          >
132	            {t('Generate another access key')}
133	          </Button>
134	        )}
135	      </div>
136	    </div>
137	  );
138	};
139	
140	/**
141	 * Displays AccessKeysDetails in a Card.
142	 * Create Another Accesskey if only one Accesskey exists
143	 * @param userName @param iamClient @param fresh @param triggerRefresh
144	 */
145	export const AccessKeysDetails: React.FC<IamAccesskeysDetailsProps> = ({
146	  obj,
147	}) => {
148	  const { userName, iamClient, fresh, triggerRefresh } = obj;
149	
150	  return fresh ? (
151	    <AccessKeysDetailsContent
152	      userName={userName}
153	      iamClient={iamClient}
154	      triggerRefresh={triggerRefresh}
155	    />
156	  ) : (
157	    <LoadingBox />
158	  );
159	};

